SELECT name
FROM seed_banks
WHERE reputation_score > 80;

SELECT name
FROM seed_banks
WHERE reputation_score = (SELECT MAX(reputation_score) FROM seed_banks);

SELECT COUNT(*) AS seed_banks_since_2010
FROM seed_banks
WHERE established_year >= 2010;

SELECT AVG(rating) AS average_rating
FROM reviews
WHERE seed_bank_id = 1;
